                        }

                        if ( size < 0 ) {
                            size = -size /* * -1.3 */;
                        }
                        int objIndex = 0;

                        fontHeight = size;

                        Font f = new Font(face, style, (int)size);
                        f = f.deriveFont(size);

                        int underline = mr.elementAt( 4 );
